/// Collect all completable properties from a schema at the given pointer path.
///
/// Follows `$ref` and merges `allOf` branches. Returns an empty vec if the
/// resolved subschema is not an object schema or the pointer cannot be resolved.
pub fn collect_properties(root: &serde_json::Value, pointer: &[String]) -> Vec<PropertyInfo> {
    let mut props: Vec<PropertyInfo> = Vec::new();
    for subschema in resolve_completion_subschemas(root, root, pointer, HashSet::new(), 0) {
        collect_properties_from(root, subschema, &mut props, 0);
    }
    props
}

/// Recursively collect properties from a schema, merging composition branches.
fn collect_properties_from(
    root: &serde_json::Value,
    schema: &serde_json::Value,
    props: &mut Vec<PropertyInfo>,
    depth: usize,
) {
    if depth > MAX_SCHEMA_DEPTH {
        return;
    }

    // Follow $ref.
    let mut visited = HashSet::new();
    let Some(schema) = follow_ref(root, schema, &mut visited) else {
        return;
    };

    // Collect required set for this schema.
    let required: HashSet<&str> = schema
        .get("required")
        .and_then(|v| v.as_array())
        .map(|arr| arr.iter().filter_map(|v| v.as_str()).collect())
        .unwrap_or_default();

    // Collect properties.
    if let Some(properties) = schema.get("properties").and_then(|v| v.as_object()) {
        for (name, prop_schema) in properties {
            // Follow $ref on the property schema for metadata.
            let mut prop_visited = HashSet::new();
            let resolved_prop =
                follow_ref(root, prop_schema, &mut prop_visited).unwrap_or(prop_schema);

            let description = format_annotation(resolved_prop);
            let schema_type = format_schema_types(resolved_prop);
            let is_required = required.contains(name.as_str());

            if let Some(existing) = props.iter_mut().find(|prop| prop.name == *name) {
                existing.required |= is_required;
                if existing.description.is_none() {
                    existing.description = description;
                }
                merge_schema_type(&mut existing.schema_type, schema_type);
            } else {
                props.push(PropertyInfo {
                    name: name.clone(),
                    required: is_required,
                    description,
                    schema_type,
                });
            }
        }
    }

    for keyword in ["allOf", "anyOf", "oneOf"] {
        if let Some(branches) = schema.get(keyword).and_then(|v| v.as_array()) {
            for branch in branches {
                collect_properties_from(root, branch, props, depth + 1);
            }
        }
    }
}

fn schema_types(schema: &serde_json::Value) -> Vec<&str> {
    match schema.get("type") {
        Some(serde_json::Value::String(value)) => vec![value.as_str()],
        Some(serde_json::Value::Array(values)) => values.iter().filter_map(|v| v.as_str()).collect(),
        _ => Vec::new(),
    }
}

fn format_schema_types(schema: &serde_json::Value) -> Option<String> {
    let types = schema_types(schema);
    (!types.is_empty()).then(|| types.join(" | "))
}

fn merge_schema_type(existing: &mut Option<String>, incoming: Option<String>) {
    let Some(incoming) = incoming else {
        return;
    };
    let Some(current) = existing else {
        *existing = Some(incoming);
        return;
    };
    for schema_type in incoming.split(" | ") {
        if !current.split(" | ").any(|value| value == schema_type) {
            current.push_str(" | ");
            current.push_str(schema_type);
        }
    }
}

/// Format title and description from a schema node into a single string.
fn format_annotation(schema: &serde_json::Value) -> Option<String> {
    let title = schema.get("title").and_then(|v| v.as_str());
    let description = schema.get("description").and_then(|v| v.as_str());
    match (title, description) {
        (Some(t), Some(d)) => Some(format!("{t}: {d}")),
        (Some(t), None) => Some(t.to_string()),
        (None, Some(d)) => Some(d.to_string()),
        (None, None) => None,
    }
}

/// Collect possible value suggestions for a property at the given pointer path.
///
/// Navigates to the subschema at `pointer` + `property_name`, then inspects
/// `enum`, `const`, and `type` to generate value suggestions.
pub fn collect_values(
    root: &serde_json::Value,
    pointer: &[String],
    property_name: &str,
) -> Vec<ValueSuggestion> {
    let mut full_pointer: Vec<String> = pointer.to_vec();
    full_pointer.push(property_name.to_string());

    let mut suggestions = Vec::new();
    for subschema in
        resolve_completion_subschemas(root, root, &full_pointer, HashSet::new(), 0)
    {
        collect_values_from(root, subschema, &mut suggestions, 0);
    }
    suggestions
}

fn collect_values_from(
    root: &serde_json::Value,
    schema: &serde_json::Value,
    suggestions: &mut Vec<ValueSuggestion>,
    depth: usize,
) {
    if depth > MAX_SCHEMA_DEPTH {
        return;
    }
    let mut visited = HashSet::new();
    let Some(schema) = follow_ref(root, schema, &mut visited) else {
        return;
    };

    if let Some(const_val) = schema.get("const") {
        suggestions.push(ValueSuggestion::Const(const_val.clone()));
    } else if let Some(enum_vals) = schema.get("enum").and_then(|v| v.as_array()) {
    if let Some(enum_vals) = subschema.get("enum").and_then(|v| v.as_array()) {
        for val in enum_vals {
            suggestions.push(ValueSuggestion::Enum(val.clone()));
        }
    } else {
        for type_str in schema_types(schema) {
            match type_str {
            "boolean" => suggestions.push(ValueSuggestion::Boolean),
            "null" => suggestions.push(ValueSuggestion::Null),
            _ => {}
            }
        }
    }

    for keyword in ["allOf", "anyOf", "oneOf"] {
        if let Some(branches) = schema.get(keyword).and_then(|v| v.as_array()) {
            for branch in branches {
                collect_values_from(root, branch, suggestions, depth + 1);
            }
        }
    }
}

