// Scanner state.
let mut in_string = false;
let mut escape = false;
let mut in_line_comment = false;
let mut in_block_comment = false;

// Stack tracking container nesting.
struct Level {
    is_object: bool,
    /// True after `:` is seen, cleared by `,`.
    after_colon: bool,
    /// Byte range (start, end exclusive) of the last completed key string
    /// at this level (content inside the quotes, not including quotes).
    last_key_content: Option<(usize, usize)>,
    /// JSON pointer segment from the parent to this container.
    parent_segment: Option<String>,
    /// Index of the current array element.
    array_index: usize,
}
let mut stack: Vec<Level> = Vec::new();

// Track the start of the current string (byte after the opening `"`).
let mut string_content_start: usize = 0;

let mut i = 0;
while i < end {
    let b = bytes[i];

    if in_line_comment {
        if b == b'\n' {
            in_line_comment = false;
        }
        i += 1;
        continue;
    }

    if in_block_comment {
        if b == b'*' && i + 1 < end && bytes[i + 1] == b'/' {
            in_block_comment = false;
            i += 2;
            continue;
        }
        i += 1;
        continue;
    }

    if in_string {
        if escape {
            escape = false;
            i += 1;
            continue;
        }
        if b == b'\\' {
            escape = true;
            i += 1;
            continue;
        }
        if b == b'"' {
            // String closed.
            if let Some(level) = stack.last_mut()
                && level.is_object
            {
                if !level.after_colon {
                    // This string was a property key.
                    level.last_key_content = Some((string_content_start, i));
                } else {
                    // This string was a property value; value consumed.
                    level.after_colon = false;
                }
            }
            in_string = false;
        }
        i += 1;
        continue;
    }

    // Not in string, not in comment.
    match b {
        b'/' if i + 1 < end => match bytes[i + 1] {
            b'/' => {
                in_line_comment = true;
                i += 2;
                continue;
            }
            b'*' => {
                in_block_comment = true;
                i += 2;
                continue;
            }
            _ => {}
        },
        b'"' => {
            in_string = true;
            string_content_start = i + 1;
        }
        b'{' => {
            let parent_segment = stack.last().and_then(|parent| {
                if parent.is_object && parent.after_colon {
                    parent
                        .last_key_content
                        .map(|(s, e)| source[s..e].to_string())
                } else if !parent.is_object {
                    Some(parent.array_index.to_string())
                } else {
                    None
                }
            });
            stack.push(Level {
                is_object: true,
                after_colon: false,
                last_key_content: None,
                parent_segment,
                array_index: 0,
            });
        }
        b'[' => {
            let parent_segment = stack.last().and_then(|parent| {
                if parent.is_object && parent.after_colon {
                    parent
                        .last_key_content
                        .map(|(s, e)| source[s..e].to_string())
                } else if !parent.is_object {
                    Some(parent.array_index.to_string())
                } else {
                    None
                }
            });
            stack.push(Level {
                is_object: false,
                after_colon: false,
                last_key_content: None,
                parent_segment,
                array_index: 0,
            });
        }
        b'}' | b']' => {
            stack.pop();
            // After closing a nested container that was a value, reset the
            // parent's after_colon so the parent is back in key position.
            if let Some(level) = stack.last_mut()
                && level.is_object
                && level.after_colon
            {
                level.after_colon = false;
            }
        }
        b':' => {
            if let Some(level) = stack.last_mut()
                && level.is_object
            {
                level.after_colon = true;
            }
        }
        b',' => {
            if let Some(level) = stack.last_mut() {
                level.after_colon = false;
                if level.is_object {
                    level.last_key_content = None;
                } else {
                    level.array_index += 1;
                }
            }
        }
        _ => {}
    }

    i += 1;
}

// Determine the context at the cursor position.
if in_line_comment || in_block_comment {
    return None;
}

// Build the pointer path from the stack (skip root level, collect parent segments).
let build_pointer = |stack: &[Level]| -> Vec<String> {
    stack
        .iter()
        .skip(1)
        .filter_map(|l| l.parent_segment.clone())
        .collect()
};

// Find the innermost object level (skip any array levels on top).
let innermost_object = stack.iter().rposition(|l| l.is_object);

// Whether the cursor is inside a string or on whitespace/structural tokens,
// the context determination is the same: check the innermost object level.
let obj_idx = innermost_object?;
let level = &stack[obj_idx];
let pointer = build_pointer(&stack[..=obj_idx]);

// When the cursor is inside a string, the replacement should start at the
// opening quote so a text_edit can replace the auto-paired `""` pair.
let replace_start = if in_string {
    string_content_start - 1
} else {
    byte_offset
};

if level.after_colon {
    let property_name = level
        .last_key_content
        .map(|(s, e)| source[s..e].to_string())
        .unwrap_or_default();
    Some(CompletionContext::PropertyValue {
        property_name,
        pointer,
        replace_start,
    })

