+fn value_suggestion_values(suggestion: &ValueSuggestion) -> Vec<serde_json::Value> {
+    match suggestion {
+        ValueSuggestion::Enum(value) | ValueSuggestion::Const(value) => vec![value.clone()],
+        ValueSuggestion::Boolean => {
+            vec![
+                serde_json::Value::Bool(true),
+                serde_json::Value::Bool(false),
+            ]
+        }
+        ValueSuggestion::Null => vec![serde_json::Value::Null],
