+fn resolve_completion_subschemas<'a>(
+    root: &'a serde_json::Value,
+    schema: &'a serde_json::Value,
+    pointer: &[String],
+    mut visited: HashSet<String>,
+    depth: usize,
+) -> Vec<&'a serde_json::Value> {
+    if depth > MAX_SCHEMA_DEPTH {
+        return Vec::new();
+    }
+    let Some(schema) = follow_ref(root, schema, &mut visited) else {
+        return Vec::new();
+    };
+    if pointer.is_empty() {
+        return vec![schema];
+    }
+
+    let segment = &pointer[0];
+    let rest = &pointer[1..];
+    let mut matches = Vec::new();
+    if let Some(prop_schema) = schema
+        .get("properties")
+        .and_then(|properties| properties.get(segment))
+    {
+        matches.extend(resolve_completion_subschemas(
+            root,
+            prop_schema,
+            rest,
+            visited.clone(),
+            depth + 1,
+        ));
+    }
+    for keyword in ["allOf", "anyOf", "oneOf"] {
+        if let Some(branches) = schema.get(keyword).and_then(|v| v.as_array()) {
+            for branch in branches {
+                matches.extend(resolve_completion_subschemas(
+                    root,
+                    branch,
+                    pointer,
+                    visited.clone(),
+                    depth + 1,
+                ));
+            }
+        }
+    }
+    if let Ok(index) = segment.parse::<usize>() {
+        if let Some(prefix_item) = schema
+            .get("prefixItems")
+            .and_then(|items| items.as_array())
+            .and_then(|items| items.get(index))
+        {
+            matches.extend(resolve_completion_subschemas(
+                root,
+                prefix_item,
+                rest,
+                visited.clone(),
+                depth + 1,
+            ));
+        } else if let Some(items) = schema.get("items")
+            && (items.is_object() || items.is_boolean())
+        {
+            matches.extend(resolve_completion_subschemas(
+                root,
+                items,
+                rest,
+                visited,
+                depth + 1,
+            ));
+        }
+    }
+    matches
 }

